script:
frappe.ui.form.on('customer_grc', {
	after_save: function(frm) {

		    // Vérifie si un avancement existe déjà pour cette entreprise
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'avancement',
                    filters: {'entreprise': frm.doc.name},
                    fields: ['name']
                },
                callback: function(r) {
                    if(!r.exc && r.message.length === 0) {
                        // Crée le nouveau document avancement
                        frappe.call({
                            method: 'frappe.client.insert',
                            args: {
                                doc: {
                                    doctype: 'avancement',
                                    entreprise: frm.doc.name,
                                    etape: 'Formation'
                                }
                            },
                            callback: function(response) {
                                if(!response.exc) {
                                    // Affiche un message de confirmation
                                    frappe.show_alert({
                                        message: __('Document avancement créé'),
                                        indicator: 'green'
                                    }, 5);
                                    
                                    // Actualise le formulaire
                                    frm.reload_doc();
                                }
                            }
                        });
                    }
                }
            });
        
		    

	}
})
